#include<bits/stdc++.h>
using namespace std;
int n, a[1005],ans=0;
int main() {
	cin >> n;
	for (int i = 1; i <= n; i++) {
		cin >> a[i];
	}
	for (int i = 1; i <= n; i++) {
		for(int j=1;j<n;j++){
			if(a[j]>a[j+1]){
				int temp=a[j];
				a[j]=a[j+1];
				a[j+1]=temp;
				ans++;
			}
		}
	}
	cout<<ans;
	return 0;
}
